#include "./util/timer/timer.h"
#include "./util/num/num.h"

#include "./main.h"

#ifdef __cplusplus
extern "C" {
#endif
void kernel_gpu_cuda_wrapper(par_str parms_cpu,
                             dim_str dim_cpu,
                             box_str* box_cpu,
                             FOUR_VECTOR* rv_cpu,
                             fp* qv_cpu,
